/**
 * 全局错误处理中间件
 *
 * 提供统一的错误处理机制，包括异步路由错误包装器、
 * 全局错误处理中间件和未捕获异常处理
 */

const logger = require('../config/logger');
const config = require('../config/env');

/**
 * 异步路由错误处理包装器
 * 自动捕获async函数中的未处理异常并传递给错误处理中间件
 *
 * @param {Function} fn - 异步路由处理函数
 * @returns {Function} - 包装后的路由处理函数
 */
function asyncHandler(fn) {
  return (req, res, next) => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

/**
 * 全局错误处理中间件
 * 处理所有未被路由捕获的错误
 *
 * @param {Error} err - 错误对象
 * @param {Object} req - Express请求对象
 * @param {Object} res - Express响应对象
 * @param {Function} next - Express next函数
 */
function globalErrorHandler(err, req, res, next) {
  // 记录详细的错误信息
  logger.error('未捕获的错误:', {
    message: err.message,
    stack: err.stack,
    url: req.originalUrl,
    method: req.method,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    userId: req.user?.id,
    timestamp: new Date().toISOString(),
    errorType: err.constructor.name,
  });

  // 确定错误状态码
  let statusCode = err.status || err.statusCode || 500;

  // 处理特定类型的错误
  if (err.name === 'ValidationError') {
    statusCode = 400;
  } else if (err.name === 'UnauthorizedError' || err.message.includes('unauthorized')) {
    statusCode = 401;
  } else if (err.name === 'ForbiddenError' || err.message.includes('forbidden')) {
    statusCode = 403;
  } else if (err.name === 'NotFoundError' || err.message.includes('not found')) {
    statusCode = 404;
  }

  // 构建错误响应
  const isDevelopment = !config.isProduction();
  const errorResponse = {
    error: isDevelopment ? err.message : getProductionErrorMessage(statusCode),
    timestamp: new Date().toISOString(),
    path: req.originalUrl,
    method: req.method,
  };

  // 在开发环境中包含更多调试信息
  if (isDevelopment) {
    errorResponse.stack = err.stack;
    errorResponse.details = err.details || null;
  }

  // 发送错误响应
  res.status(statusCode).json(errorResponse);
}

/**
 * 获取生产环境友好的错误消息
 *
 * @param {number} statusCode - HTTP状态码
 * @returns {string} - 用户友好的错误消息
 */
function getProductionErrorMessage(statusCode) {
  switch (statusCode) {
    case 400:
      return '请求参数错误';
    case 401:
      return '身份验证失败，请重新登录';
    case 403:
      return '权限不足，无法访问此资源';
    case 404:
      return '请求的资源不存在';
    case 429:
      return '请求过于频繁，请稍后重试';
    case 500:
    default:
      return '服务器内部错误，请稍后重试';
  }
}

/**
 * 404错误处理中间件
 * 处理未匹配到任何路由的请求
 */
function notFoundHandler(req, res, next) {
  const error = new Error(`路由 ${req.originalUrl} 不存在`);
  error.status = 404;
  next(error);
}

/**
 * 初始化全局错误处理
 * 设置未捕获异常和Promise拒绝的处理器
 */
function initializeErrorHandling() {
  // 处理未捕获的Promise拒绝
  process.on('unhandledRejection', (reason, promise) => {
    logger.error('未处理的Promise拒绝:', {
      reason: reason,
      promise: promise,
      stack: reason?.stack,
      timestamp: new Date().toISOString(),
    });

    // 在生产环境中，记录错误但不退出进程
    // 在开发环境中，可以选择退出进程以便调试
    if (!config.isProduction()) {
      console.error('未处理的Promise拒绝，进程将在5秒后退出...');
      setTimeout(() => {
        process.exit(1);
      }, 5000);
    }
  });

  // 处理未捕获的异常
  process.on('uncaughtException', error => {
    logger.error('未捕获的异常:', {
      message: error.message,
      stack: error.stack,
      timestamp: new Date().toISOString(),
    });

    // 未捕获的异常通常表示严重问题，应该退出进程
    console.error('未捕获的异常，进程将退出...');
    process.exit(1);
  });

  // 处理进程退出信号
  process.on('SIGTERM', () => {
    logger.info('收到SIGTERM信号，正在优雅关闭...');
    // 这里可以添加清理逻辑
    process.exit(0);
  });

  process.on('SIGINT', () => {
    logger.info('收到SIGINT信号，正在优雅关闭...');
    // 这里可以添加清理逻辑
    process.exit(0);
  });
}

/**
 * 创建带有重试机制的异步处理器
 *
 * @param {Function} fn - 异步函数
 * @param {number} maxRetries - 最大重试次数
 * @param {number} retryDelay - 重试延迟（毫秒）
 * @returns {Function} - 包装后的函数
 */
function asyncHandlerWithRetry(fn, maxRetries = 3, retryDelay = 1000) {
  return asyncHandler(async (req, res, next) => {
    let lastError;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await fn(req, res, next);
      } catch (error) {
        lastError = error;

        // 如果是客户端错误（4xx），不重试
        if (error.status && error.status >= 400 && error.status < 500) {
          throw error;
        }

        // 如果不是最后一次尝试，等待后重试
        if (attempt < maxRetries) {
          logger.warn(`操作失败，第${attempt}次重试...`, {
            error: error.message,
            url: req.originalUrl,
            attempt: attempt,
            maxRetries: maxRetries,
          });

          await new Promise(resolve => setTimeout(resolve, retryDelay * attempt));
        }
      }
    }

    // 所有重试都失败，抛出最后一个错误
    throw lastError;
  });
}

module.exports = {
  asyncHandler,
  asyncHandlerWithRetry,
  globalErrorHandler,
  notFoundHandler,
  initializeErrorHandling,
};

const express = require('express');
const router = express.Router();
const { body, validationResult } = require('express-validator');
const db = require('../db/database');
const logger = require('../config/logger');
const {
  ROLES,
  generateAccessToken,
  generateRefreshToken,
  hashPassword,
  verifyPassword,
  refreshAccessToken,
  authenticateToken,
} = require('../utils/auth');

// 用户登录验证规则
const loginValidation = [
  body('email').notEmpty().trim().isLength({ min: 1, max: 255 }).withMessage('用户名/邮箱不能为空'),
  body('password').notEmpty().isLength({ min: 4 }).trim().withMessage('密码不能为空且至少4个字符'),
  body('role').optional().isIn(Object.values(ROLES)),
];

// 刷新token验证规则
const refreshValidation = [body('refreshToken').notEmpty().trim()];

// 处理验证错误
function handleValidationErrors(req, res) {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  return null;
}

// 用户登录（仅支持用户名+密码登录）
router.post('/login', loginValidation, async (req, res) => {
  const validationError = handleValidationErrors(req, res);
  if (validationError) {
    return;
  }

  const { email, password, role = ROLES.USER } = req.body;

  try {
    // 必须提供用户名/邮箱，支持邮箱或用户名登录
    const query = 'SELECT * FROM users WHERE (email = ? OR name = ?) AND isActive = 1';
    db.get(query, [email, email], async (err, user) => {
      if (err) {
        logger.error('用户登录查询失败', { error: err.message });
        return res.status(500).json({ error: '服务器错误' });
      }

      if (!user) {
        logger.warn('用户登录失败：用户不存在或已禁用', { identifier: email, ip: req.ip });
        return res.status(401).json({ error: '用户名/邮箱或密码错误' });
      }

      // 验证密码
      const bcrypt = require('bcryptjs');
      const isValidPassword = await bcrypt.compare(password, user.password);
      if (!isValidPassword) {
        logger.warn('用户登录失败：密码错误', { identifier: email, ip: req.ip });
        return res.status(401).json({ error: '用户名/邮箱或密码错误' });
      }

      // 生成tokens
      const userInfo = {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
      };

      const accessToken = generateAccessToken(userInfo);
      const refreshToken = generateRefreshToken(userInfo);

      logger.info('用户登录成功', {
        userId: user.id,
        email: user.email,
        name: user.name,
        loginIdentifier: email,
        ip: req.ip,
      });

      return res.json({
        accessToken,
        refreshToken,
        user: userInfo,
      });
    });
  } catch (error) {
    logger.error('登录处理失败', { error: error.message, stack: error.stack });
    res.status(500).json({ error: '登录失败，请稍后重试' });
  }
});

// 供应商登录（通过accessKey）
router.post('/login/provider', [body('accessKey').notEmpty().trim()], async (req, res) => {
  const validationError = handleValidationErrors(req, res);
  if (validationError) {
    return;
  }

  const { accessKey } = req.body;

  db.get('SELECT id, name FROM providers WHERE accessKey = ?', [accessKey], (err, provider) => {
    if (err) {
      logger.error('供应商登录查询失败', { error: err.message });
      return res.status(500).json({ error: '服务器错误' });
    }

    if (!provider) {
      logger.warn('供应商登录失败：无效的accessKey', { accessKey, ip: req.ip });
      return res.status(401).json({ error: '无效的访问密钥' });
    }

    // 生成供应商用户信息
    const user = {
      id: provider.id,
      name: provider.name,
      role: ROLES.PROVIDER,
      providerId: provider.id,
    };

    // 生成tokens
    const accessToken = generateAccessToken(user);
    const refreshToken = generateRefreshToken(user);

    logger.info('供应商登录成功', {
      providerId: provider.id,
      providerName: provider.name,
      ip: req.ip,
    });

    res.json({
      accessToken,
      refreshToken,
      user: {
        id: user.id,
        name: user.name,
        role: user.role,
        providerId: user.providerId,
      },
    });
  });
});

// 刷新token
router.post('/refresh', refreshValidation, (req, res) => {
  const validationError = handleValidationErrors(req, res);
  if (validationError) {
    return;
  }

  const { refreshToken } = req.body;

  try {
    const newAccessToken = refreshAccessToken(refreshToken);

    logger.info('Token刷新成功', { ip: req.ip });

    res.json({
      accessToken: newAccessToken,
    });
  } catch (error) {
    logger.warn('Token刷新失败', { error: error.message, ip: req.ip });
    res.status(403).json({ error: 'Token刷新失败：' + error.message });
  }
});

// 登出（可选，主要用于记录）
router.post('/logout', authenticateToken, (req, res) => {
  logger.info('用户登出', {
    userId: req.user.id,
    role: req.user.role,
    ip: req.ip,
  });

  // 实际的token失效应该在客户端处理
  // 或者维护一个token黑名单（需要额外的存储）
  res.json({ message: '登出成功' });
});

// 获取当前用户信息
router.get('/me', authenticateToken, (req, res) => {
  res.json({
    user: {
      id: req.user.id,
      email: req.user.email,
      role: req.user.role,
      name: req.user.name,
      providerId: req.user.providerId,
    },
  });
});

module.exports = router;

const express = require('express');
const router = express.Router();
const db = require('../db/database');
const { body, validationResult } = require('express-validator');
const logger = require('../config/logger');
const { spawn } = require('child_process');
const path = require('path');
const fs = require('fs');
const multer = require('multer');
const crypto = require('crypto');
const { encrypt, decrypt } = require('../utils/encryption');

// 配置multer用于文件上传
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    const uploadDir = path.join(__dirname, '../uploads/restore');
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }
    cb(null, uploadDir);
  },
  filename: function (req, file, cb) {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    cb(null, `restore-${timestamp}-${file.originalname}`);
  },
});

const upload = multer({
  storage: storage,
  limits: {
    fileSize: 500 * 1024 * 1024, // 500MB
  },
  fileFilter: function (req, file, cb) {
    const allowedTypes = ['.tar.gz', '.zip'];
    const fileExtension = path.extname(file.originalname).toLowerCase();
    const isValidType = allowedTypes.some(type => file.originalname.toLowerCase().endsWith(type));

    if (isValidType) {
      cb(null, true);
    } else {
      cb(new Error('只支持 .tar.gz 和 .zip 格式的备份文件'));
    }
  },
});

// 获取备份配置
router.get('/config', (req, res) => {
  db.get('SELECT * FROM backup_config WHERE id = 1', (err, row) => {
    if (err) {
      logger.error('获取备份配置失败:', err.message);
      return res.status(500).json({ error: '获取备份配置失败' });
    }

    if (!row) {
      // 如果没有配置，返回默认配置
      return res.json({
        id: 1,
        qiniu_access_key: '',
        qiniu_secret_key: '',
        qiniu_bucket: '',
        qiniu_zone: 'z0',
        backup_frequency: 'daily',
        auto_backup_enabled: false,
        last_backup_time: null,
        last_backup_status: null,
        last_backup_size: null,
        retention_days: 30,
        wechat_webhook_url: '',
        notification_enabled: true,
      });
    }

    // 隐藏敏感信息
    const config = {
      ...row,
      qiniu_secret_key: row.qiniu_secret_key ? '***已配置***' : '',
      qiniu_access_key: row.qiniu_access_key ? '***已配置***' : '',
      auto_backup_enabled: Boolean(row.auto_backup_enabled),
      notification_enabled: Boolean(row.notification_enabled),
    };

    res.json(config);
  });
});

// 更新备份配置
router.put(
  '/config',
  [
    body('qiniu_access_key').optional().isLength({ min: 1 }).withMessage('AccessKey不能为空'),
    body('qiniu_bucket').optional().isLength({ min: 1 }).withMessage('存储空间名称不能为空'),
    body('qiniu_zone').isIn(['z0', 'z1', 'z2', 'na0', 'as0']).withMessage('存储区域无效'),
    body('backup_frequency').isIn(['hourly', 'daily', 'weekly']).withMessage('备份频率无效'),
    body('retention_days').isInt({ min: 1, max: 365 }).withMessage('保留天数必须在1-365之间'),
    body('auto_backup_enabled').isBoolean().withMessage('自动备份设置无效'),
    body('notification_enabled').isBoolean().withMessage('通知设置无效'),
  ],
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const {
      qiniu_access_key,
      qiniu_secret_key,
      qiniu_bucket,
      qiniu_zone,
      backup_frequency,
      auto_backup_enabled,
      retention_days,
      wechat_webhook_url,
      notification_enabled,
    } = req.body;

    // 构建更新SQL
    const updateFields = [];
    const updateValues = [];

    if (qiniu_access_key !== undefined && qiniu_access_key !== '***已配置***') {
      updateFields.push('qiniu_access_key = ?');
      updateValues.push(encrypt(qiniu_access_key));
    }

    if (qiniu_secret_key !== undefined && qiniu_secret_key !== '***已配置***') {
      updateFields.push('qiniu_secret_key = ?');
      updateValues.push(encrypt(qiniu_secret_key));
    }

    if (qiniu_bucket !== undefined) {
      updateFields.push('qiniu_bucket = ?');
      updateValues.push(qiniu_bucket);
    }

    updateFields.push(
      'qiniu_zone = ?',
      'backup_frequency = ?',
      'auto_backup_enabled = ?',
      'retention_days = ?',
      'notification_enabled = ?',
      'updated_at = ?'
    );
    updateValues.push(
      qiniu_zone,
      backup_frequency,
      auto_backup_enabled ? 1 : 0,
      retention_days,
      notification_enabled ? 1 : 0,
      new Date().toISOString()
    );

    if (wechat_webhook_url !== undefined) {
      updateFields.push('wechat_webhook_url = ?');
      updateValues.push(wechat_webhook_url);
    }

    const sql = `UPDATE backup_config SET ${updateFields.join(', ')} WHERE id = 1`;

    db.run(sql, updateValues, function (err) {
      if (err) {
        logger.error('更新备份配置失败:', err.message);
        return res.status(500).json({ error: '更新备份配置失败' });
      }

      if (this.changes === 0) {
        // 如果没有更新任何行，说明配置不存在，需要插入
        const now = new Date().toISOString();
        const insertSql = `
        INSERT INTO backup_config (
          qiniu_access_key, qiniu_secret_key, qiniu_bucket, qiniu_zone,
          backup_frequency, auto_backup_enabled, retention_days,
          wechat_webhook_url, notification_enabled, created_at, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `;

        db.run(
          insertSql,
          [
            qiniu_access_key ? encrypt(qiniu_access_key) : '',
            qiniu_secret_key ? encrypt(qiniu_secret_key) : '',
            qiniu_bucket || '',
            qiniu_zone,
            backup_frequency,
            auto_backup_enabled ? 1 : 0,
            retention_days,
            wechat_webhook_url || '',
            notification_enabled ? 1 : 0,
            now,
            now,
          ],
          err => {
            if (err) {
              logger.error('创建备份配置失败:', err.message);
              return res.status(500).json({ error: '创建备份配置失败' });
            }

            logger.info('备份配置创建成功');
            res.json({ message: '备份配置保存成功' });
          }
        );
      } else {
        logger.info('备份配置更新成功');
        res.json({ message: '备份配置保存成功' });
      }
    });
  }
);

// 测试七牛云连接
router.post('/test-connection', (req, res) => {
  db.get(
    'SELECT qiniu_access_key, qiniu_secret_key, qiniu_bucket FROM backup_config WHERE id = 1',
    (err, row) => {
      if (err || !row || !row.qiniu_access_key || !row.qiniu_secret_key || !row.qiniu_bucket) {
        return res.status(400).json({ error: '请先配置七牛云参数' });
      }

      // 创建临时配置文件
      const tempConfigPath = path.join(__dirname, '../temp_qiniu_config.json');
      const config = {
        access_key: decrypt(row.qiniu_access_key),
        secret_key: decrypt(row.qiniu_secret_key),
        bucket: row.qiniu_bucket,
      };

      fs.writeFileSync(tempConfigPath, JSON.stringify(config));

      // 执行测试脚本
      const testScript = path.join(__dirname, '../scripts/test-qiniu-connection.js');
      const child = spawn('node', [testScript, tempConfigPath], {
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      let output = '';
      let errorOutput = '';

      child.stdout.on('data', data => {
        output += data.toString();
      });

      child.stderr.on('data', data => {
        errorOutput += data.toString();
      });

      child.on('close', code => {
        // 清理临时文件
        try {
          fs.unlinkSync(tempConfigPath);
        } catch (e) {
          // 忽略清理错误
        }

        if (code === 0) {
          res.json({ success: true, message: '七牛云连接测试成功' });
        } else {
          logger.error('七牛云连接测试失败:', errorOutput);
          res.status(400).json({
            success: false,
            error: '七牛云连接测试失败',
            details: errorOutput || output,
          });
        }
      });
    }
  );
});

// 手动执行备份
router.post('/execute', (req, res) => {
  db.get('SELECT * FROM backup_config WHERE id = 1', (err, row) => {
    if (err || !row || !row.qiniu_access_key || !row.qiniu_secret_key || !row.qiniu_bucket) {
      return res.status(400).json({ error: '请先配置七牛云参数' });
    }

    // 更新备份状态为进行中
    const now = new Date().toISOString();
    db.run(
      'UPDATE backup_config SET last_backup_time = ?, last_backup_status = ? WHERE id = 1',
      [now, 'running'],
      err => {
        if (err) {
          logger.error('更新备份状态失败:', err.message);
        }
      }
    );

    // 立即返回响应，备份在后台执行
    res.json({ message: '备份任务已启动，请稍后查看结果' });

    // 执行备份脚本
    const backupScript = path.join(__dirname, '../scripts/qiniu-backup.js');
    const child = spawn('node', [backupScript], {
      stdio: ['pipe', 'pipe', 'pipe'],
      env: {
        ...process.env,
        QINIU_ACCESS_KEY: decrypt(row.qiniu_access_key),
        QINIU_SECRET_KEY: decrypt(row.qiniu_secret_key),
        QINIU_BUCKET: row.qiniu_bucket,
        QINIU_ZONE: row.qiniu_zone,
        WECHAT_WEBHOOK_URL: row.wechat_webhook_url || '',
      },
    });

    let output = '';
    let errorOutput = '';

    child.stdout.on('data', data => {
      output += data.toString();
    });

    child.stderr.on('data', data => {
      errorOutput += data.toString();
    });

    child.on('close', code => {
      const status = code === 0 ? 'success' : 'failed';
      const backupSize = extractBackupSize(output);

      // 更新备份结果
      db.run(
