  body('email').isEmail().normalizeEmail().withMessage('请输入有效的邮箱地址'),
  body('password').isLength({ min: 4 }).trim().withMessage('密码至少需要4个字符'),
  body('name')
    .notEmpty()
    .trim()
    .isLength({ min: 1, max: 100 })
    .withMessage('用户名不能为空且不超过100个字符'),
];

// 用户更新验证规则
